use super::super::all::all_curves_have_usable_phase;
use super::super::all::all_curves_share_frequency_grid;
use super::super::bass::bass_management_objective;
use super::super::compute::predict_bass_management_sum;
use super::super::misc::complex_sum_mains;
use super::super::misc::curve_has_usable_phase;
use super::super::*;
use super::misc::differential_evolution_minimize;
use super::misc::grouped_home_cinema_roles;
